VALUES
  ('aboriginal-57f41407-moex-00392', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列關於被告自白證據能力與證明力之敘述，何者正確？', '["只要被告之自白與事實相符，就有證據能力", "被告陳述其自白係出於不正之方法者，應先於其他事證而為調查", "法官得以被告之自白作為有罪判決之唯一依據", "偵查機關以不正方法取得之被告自白，仍有證據能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00393', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '小李向檢察官提起告訴，說小明在公車上偷他的錢包，事後經檢察官起訴，下列敘述何者錯誤？', '["小明受訊問時，可保持緘默", "因為小明在檢察官偵訊時已承認竊盜犯行，因此就算沒有其他證明小明有偷東西的證據，仍可認定小明有罪", "若僅有小李指訴小明有竊盜行為，但無其他補強證據，仍不能認定小明犯罪", "小明否認偷小李的錢包，但因公車監視錄影錄到小明偷錢過程，故可認定小明有罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00394', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列何者非屬刑法第10條第2項規定之公務員？', '["直轄市市長", "郵差", "警察", "於監獄擔任崗哨之替代役"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00395', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '警察甲於調查乙涉嫌強盜案件中，經約談目擊證人丙後，發現丙所述有刻意避重就輕並有維護乙之情形， 於是警告丙若不據實陳述，將會以丙涉嫌湮滅罪證偵辦，丙因不滿甲之言詞，而向地方檢察署提出告訴， 下列關於甲之行為是否成罪之敘述，何者正確？', '["甲成立恐嚇危害安全罪", "甲成立濫權追訴罪", "甲不成立犯罪", "甲成立犯罪，但其行為情堪憫恕得減輕其刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00396', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '身心健全的80歲爺爺與13歲孫子一起去偷隔壁鄰居的金項鍊，下列敘述何者正確？', '["兩人都應予刑罰，但都可以減輕其刑", "兩人都不應處以刑罰", "爺爺應予刑罰，但可減輕其刑，孫子不罰", "兩人都應予刑罰，但爺爺可以減輕其刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00397', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '警員甲以一行為觸犯公文書登載不實罪及對於違背職務之行為受賄罪，其中公文書登載不實罪業經發覺， 不符合自首，但甲於檢察官訊問時，除自白公文書登載不實犯行外，並就未經發覺之對於違背職務之行為 受賄罪，主動坦承犯行，並繳交犯罪所得，檢察官乃據以提起公訴。下列關於甲行為之論罪敘述，依實務 見解，何者正確？', '["依貪污治罪條例關於自首規定，減輕或免除其刑", "依貪污治罪條例關於自白規定，減輕其刑", "本件無從依自首或自白規定，減輕或免除其刑", "甲之行為應以公文書登載不實罪，但因該犯行業經發覺，故無從依自首規定，減輕其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00398', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲故意毆傷乙，乙因傷重死亡，甲成立何罪？', '["故意殺人罪", "僅成立過失致人於死罪", "傷害致人於死罪", "僅成立傷害罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00399', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列何者不適用刑法第19條第3項關於原因自由行為之規定？', '["甲一心一意想殺乙，故意讓自己睡著導致夢遊而殺之", "甲沒有膽量殺死乙，故意灌高粱一瓶爛醉失控而殺之", "甲為增加勇氣殺乙而喝酒，但不小心喝到爛醉失控而殺之", "甲為壯膽殺乙而吸食安非他命，但不小心吸到過量毒癮發作失控而殺之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00400', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '共同正犯中一人所引起之加重結果，其他行為人是否同負加重結果之全部刑責，應如何判斷？', '["一律成立加重結果犯", "一律不成立加重結果犯", "視其他行為人就此加重結果之發生，有無故意為斷", "視其他行為人就此加重結果之發生，能否預見為斷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00401', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族委員會組織法，下列事項何者非原住民族委員會掌理？', '["原住民工作權保障之規劃、協調及推動", "原住民族地區部落基礎建設之規劃、協調及推動", "原住民傳統生物多樣性知識的調查、規劃及協調", "原住民族與國家關係之規劃、協調及推動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
